@using sv_7b2d96df1c5a4d999137d4173f2da141.Services
@inject ISettingsService SettingsService

<div class="profile-section">
    <h4 class="mb-4">Profile Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (_profile is not null)
    {
        <div class="row g-4">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="card text-center p-3">
                    <label class="form-label fw-semibold">Avatar Preview</label>
                    <div class="avatar-preview mx-auto mb-2">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="rounded-circle img-fluid" style="width:96px;height:96px;object-fit:cover;" />
                        }
                        else
                        {
                            <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                                 style="width:96px;height:96px;">
                                <span class="text-white fs-1">@(_displayName?.Length > 0 ? _displayName[0].ToString().ToUpper() : "?")</span>
                            </div>
                        }
                    </div>
                    <small class="text-muted text-break">@_avatarUrl</small>
                </div>
            </div>
        </div>

        <hr />

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
                <span class="me-2">✅</span> @_successMessage
            </div>
        }

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3 d-flex align-items-center" role="alert">
                <span class="me-2">❌</span> @_errorMessage
            </div>
        }
    }
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadAsync();
    }

    private async Task LoadAsync()
    {
        _loading = true;
        try
        {
            _profile = await SettingsService.GetProfileAsync();
            PopulateFields(_profile);
        }
        finally
        {
            _loading = false;
        }
    }

    private void PopulateFields(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _successMessage = "Profile saved successfully.";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save profile: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            PopulateFields(_profile);
        }
        _successMessage = null;
        _errorMessage = null;
    }
}

@using sv_7b2d96df1c5a4d999137d4173f2da141.Services
@inject ISettingsService SettingsService

<div class="notifications-section">
    <h4 class="mb-4">Notification Preferences</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">General</h6>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" role="switch" id="emailNotif"
                           @bind="_emailNotifications" />
                    <label class="form-check-label" for="emailNotif">Email Notifications</label>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" role="switch" id="pushNotif"
                           @bind="_pushNotifications" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>

                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch" id="weeklyDigest"
                           @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h6 class="card-title mb-3">Muted Channels</h6>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _allChannels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                        </div>
                    }
                }
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-3">✅ @_successMessage</div>
        }

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger mt-3">❌ @_errorMessage</div>
        }
    }
</div>

@code {
    /// <summary>All known channel names so the user can mute/unmute any of them.</summary>
    [Parameter]
    public List<string> AvailableChannels { get; set; } = ["general", "announcements", "engineering", "design", "random"];

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = [.. prefs.MutedChannels];

            _allChannels = AvailableChannels
                .Union(prefs.MutedChannels)
                .Distinct()
                .OrderBy(c => c)
                .ToList();
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _successMessage = "Notification preferences saved.";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_7b2d96df1c5a4d999137d4173f2da141.Services
@inject ISettingsService SettingsService

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (_security is not null)
    {
        @* ── Change Password Panel ── *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button"
                 @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <h6 class="mb-0">Change Password</h6>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="alert alert-success py-2">@_passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* ── Two-Factor Authentication ── *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        @* ── Active Sessions ── *@
        <div class="card mb-4">
            <div class="card-header">
                <h6 class="mb-0">Active Sessions</h6>
            </div>
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session != _sessions.FirstOrDefault())
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        @* ── Revoke Confirmation Dialog ── *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop show" @onclick="CancelRevoke"></div>
            <div class="modal d-block" tabindex="-1" @onclick:stopPropagation>
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>
                                Are you sure you want to revoke the session on
                                <strong>@_sessionToRevoke.Device</strong> in
                                <strong>@_sessionToRevoke.Location</strong>?
                            </p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }

        @if (_revokeMessage is not null)
        {
            <div class="alert alert-success mt-3">✅ @_revokeMessage</div>
        }
    }
</div>

@code {
    private SecuritySettings? _security;
    private List<ActiveSession> _sessions = [];
    private bool _twoFactorEnabled;
    private bool _loading = true;

    // Password change
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;
    private string? _passwordSuccess;

    // Session revocation
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private string? _revokeMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            _security = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = _security.TwoFactorEnabled;
            _sessions = [.. _security.Sessions];
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = "Password updated successfully.";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordError = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _revokeMessage = null;
    }

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _revokeMessage = $"Session on {_sessionToRevoke.Device} revoked.";
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _revokeMessage = null;
            _passwordError = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            _revoking = false;
        }
    }
}

