<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (_security is not null)
    {
        @* ── Change Password Panel ── *@
        <div class="card mb-4">
            <div class="card-header d-flex justify-content-between align-items-center"
                 role="button"
                 @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <h6 class="mb-0">Change Password</h6>
                <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="mb-3">
                        <label class="form-label">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Confirm New Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>

                    @if (_passwordError is not null)
                    {
                        <div class="alert alert-danger py-2">@_passwordError</div>
                    }
                    @if (_passwordSuccess is not null)
                    {
                        <div class="alert alert-success py-2">@_passwordSuccess</div>
                    }

                    <button class="btn btn-primary" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        @* ── Two-Factor Authentication ── *@
        <div class="card mb-4">
            <div class="card-body d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@_twoFactorEnabled"
                           @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                </div>
            </div>
        </div>

        @* ── Active Sessions ── *@
        <div class="card mb-4">
            <div class="card-header">
                <h6 class="mb-0">Active Sessions</h6>
            </div>
            <div class="table-responsive">
                <table class="table table-hover mb-0">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session != _sessions.FirstOrDefault())
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        </div>

        @* ── Revoke Confirmation Dialog ── *@
        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop show" @onclick="CancelRevoke"></div>
            <div class="modal d-block" tabindex="-1" @onclick:stopPropagation>
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header">
                            <h5 class="modal-title">Revoke Session</h5>
                            <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                        </div>
                        <div class="modal-body">
                            <p>
                                Are you sure you want to revoke the session on
                                <strong>@_sessionToRevoke.Device</strong> in
                                <strong>@_sessionToRevoke.Location</strong>?
                            </p>
                        </div>
                        <div class="modal-footer">
                            <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                            <button class="btn btn-danger" @onclick="ConfirmRevokeAsync" disabled="@_revoking">
                                @if (_revoking)
                                {
                                    <span class="spinner-border spinner-border-sm me-1"></span>
                                }
                                Revoke
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        }

        @if (_revokeMessage is not null)
        {
            <div class="alert alert-success mt-3">✅ @_revokeMessage</div>
        }
    }
</div>

@code {
    private SecuritySettings? _security;
    private List<ActiveSession> _sessions = [];
    private bool _twoFactorEnabled;
    private bool _loading = true;

    // Password change
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private string? _passwordError;
    private string? _passwordSuccess;

    // Session revocation
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private string? _revokeMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            _security = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = _security.TwoFactorEnabled;
            _sessions = [.. _security.Sessions];
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _passwordSuccess = "Password updated successfully.";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _passwordError = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _revokeMessage = null;
    }

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions.RemoveAll(s => s.Id == _sessionToRevoke.Id);
            _revokeMessage = $"Session on {_sessionToRevoke.Device} revoked.";
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            _revokeMessage = null;
            _passwordError = $"Failed to revoke session: {ex.Message}";
        }
        finally
        {
            _revoking = false;
        }
    }
}

