@code {
    /// <summary>All known channel names so the user can mute/unmute any of them.</summary>
    [Parameter]
    public List<string> AvailableChannels { get; set; } = ["general", "announcements", "engineering", "design", "random"];

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private List<string> _allChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = [.. prefs.MutedChannels];

            _allChannels = AvailableChannels
                .Union(prefs.MutedChannels)
                .Distinct()
                .OrderBy(c => c)
                .ToList();
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _successMessage = "Notification preferences saved.";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}
