@using sv_7b2d96df1c5a4d999137d4173f2da141.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else
    {
        <div class="row g-4">
            <div class="col-md-7">
                @* ── Theme ── *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")"
                                       value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                @* ── Font Size ── *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")"
                                       value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                @* ── Language ── *@
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            <option value="en">English</option>
                            <option value="es">Español</option>
                            <option value="fr">Français</option>
                            <option value="de">Deutsch</option>
                            <option value="ja">日本語</option>
                        </select>
                    </div>
                </div>

                @* ── Compact Mode ── *@
                <div class="card mb-4">
                    <div class="card-body d-flex justify-content-between align-items-center">
                        <div>
                            <h6 class="mb-0">Compact Mode</h6>
                            <small class="text-muted">Reduce spacing and padding throughout the UI</small>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save
                </button>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success mt-3">✅ @_successMessage</div>
                }
                @if (_errorMessage is not null)
                {
                    <div class="alert alert-danger mt-3">❌ @_errorMessage</div>
                }
            </div>

            @* ── Live Preview ── *@
            <div class="col-md-5">
                <div class="card">
                    <div class="card-header">
                        <h6 class="mb-0">Live Preview</h6>
                    </div>
                    <div class="card-body preview-area @PreviewThemeClass" style="@PreviewFontStyle">
                        <div class="@(_compactMode ? "p-1" : "p-3")">
                            <h5>Sample Heading</h5>
                            <p class="@(_compactMode ? "mb-1" : "mb-3")">
                                This is a preview of how your content will look with the selected settings.
                            </p>
                            <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                                <button class="btn btn-sm btn-primary">Primary</button>
                                <button class="btn btn-sm btn-outline-secondary">Secondary</button>
                            </div>
                            <ul class="list-group">
                                <li class="list-group-item @PreviewListItemClass @(_compactMode ? "py-1" : "")">Item One</li>
                                <li class="list-group-item @PreviewListItemClass @(_compactMode ? "py-1" : "")">Item Two</li>
                                <li class="list-group-item @PreviewListItemClass @(_compactMode ? "py-1" : "")">Item Three</li>
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "bg-dark text-white",
        "System" => "bg-body-secondary",
        _ => "bg-white text-dark"
    };

    private string PreviewListItemClass => _theme == "Dark"
        ? "bg-dark text-white border-secondary"
        : "";

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.15rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _successMessage = "Appearance settings saved.";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

.preview-area {
    border-radius: 0.5rem;
    transition: background-color 0.3s, color 0.3s, font-size 0.3s;
    min-height: 220px;
}

